// POST /api/levels/:levelId/complete
app.post('/api/levels/:levelId/complete', authenticatePlayer, (req, res) => {
  const levelId = parseInt(req.params.levelId, 10);
  const { score, time, moves, combo } = req.body;

  // Validate input
  const validationErrors = validateCompletionData(levelId, score, time);
  if (validationErrors.length > 0) {
    return res.status(400).json({
      success: false,
      errors: validationErrors,
    });
  }

  const player = getOrCreatePlayer(req.playerId);

  // Check level unlock (must complete previous level first, except level 1)
  if (levelId > 1 && !player.levelsCompleted[levelId - 1]) {
    return res.status(403).json({
      success: false,
      error: `Level ${levelId} is locked. Complete level ${levelId - 1} first.`,
    });
  }

  // Calculate stars and rewards
  const stars = calculateStars(levelId, score);
  const rewards = calculateRewards(levelId, stars);

  if (stars === 0) {
    return res.status(200).json({
      success: true,
      data: {
        levelId,
        passed: false,
        stars: 0,
        score,
        time,
        rewards: { coins: 0, gems: 0 },
        message: 'Level not passed. Try again!',
      },
    });
  }

  // Track previous best
  const previousBest = player.levelsCompleted[levelId] || null;
  const previousStars = previousBest ? previousBest.stars : 0;
  const isNewCompletion = !previousBest;
  const isImprovement = stars > previousStars;

  // Only award incremental rewards for star improvements
  let awardedRewards = { coins: 0, gems: 0 };

  if (isNewCompletion) {
    awardedRewards = { ...rewards };
  } else if (isImprovement) {
    // Award difference between new and old reward tiers
    const oldRewards = calculateRewards(levelId, previousStars);
    awardedRewards = {
      coins: Math.max(0, rewards.coins - oldRewards.coins),
      gems: Math.max(0, rewards.gems - oldRewards.gems),
    };
  }
  // If no improvement, no additional rewards

  // Apply time bonus (faster = more coins, up to 50% bonus)
  const config = LEVEL_CONFIG[levelId];
  const timeRatio = Math.max(0, 1 - (time / config.maxTime));
  const timeBonus = Math.floor(awardedRewards.coins * timeRatio * 0.5);
  awardedRewards.coins += timeBonus;

  // Update player state
  player.coins += awardedRewards.coins;
  player.gems += awardedRewards.gems;

  // Update star count
  if (isImprovement || isNewCompletion) {
    player.totalStars += (stars - previousStars);
  }

  // Store completion record
  const completionRecord = {
    levelId,
    score,
    time,
    moves: moves || null,
    combo: combo || null,
    stars,
    completedAt: new Date().toISOString(),
  };

  // Only update best if it's an improvement
  if (isNewCompletion || isImprovement || (score > (previousBest?.bestScore || 0))) {
    player.levelsCompleted[levelId] = {
      stars: Math.max(stars, previousStars),
      bestScore: Math.max(score, previousBest?.bestScore || 0),
      bestTime: previousBest ? Math.min(time, previousBest.bestTime) : time,
      completionCount: (previousBest?.completionCount || 0) + 1,
      firstCompletedAt: previousBest?.firstCompletedAt || completionRecord.completedAt,
      lastCompletedAt: completionRecord.completedAt,
    };
  } else if (previousBest) {
    player.levelsCompleted[levelId].completionCount += 1;
    player.levelsCompleted[levelId].lastCompletedAt = completionRecord.completedAt;
  }

  // Store in completion history
  const completionId = crypto.randomUUID();
  if (!levelCompletions[req.playerId]) {
    levelCompletions[req.playerId] = [];
  }
  levelCompletions[req.playerId].push({ id: completionId, ...completionRecord });

  // Check for milestone rewards that were newly unlocked
  const newMilestones = [];
  for (const [threshold, milestoneReward] of Object.entries(MILESTONE_REWARDS)) {
    const thresholdNum = parseInt(threshold, 10);
    if (player.totalStars >= thresholdNum && (player.totalStars - (stars - previousStars)) < thresholdNum) {
      newMilestones.push({
        starsRequired: thresholdNum,
        reward: milestoneReward,
      });
    }
  }

  // Determine if next level is now unlocked
  const nextLevelId = levelId + 1;
  const nextLevelUnlocked = LEVEL_CONFIG[nextLevelId] && isNewCompletion;

  res.json({
    success: true,
    data: {
      completionId,
      levelId,
      passed: true,
      stars,
      previousStars,
      isNewRecord: isImprovement,
      score,
      time,
      timeBonus,
      rewards: awardedRewards,
      playerState: {
        coins: player.coins,
        gems: player.gems,
        totalStars: player.totalStars,
      },
      nextLevelUnlocked: nextLevelUnlocked ? nextLevelId : null,
      newMilestones,
      message: isImprovement
        ? `New record! ${stars} stars earned!`
        : isNewCompletion
          ? `Level ${levelId} completed with ${stars} stars!`
          : `Level replayed. ${stars === previousStars ? 'Same score.' : 'No improvement.'}`,
    },
  });
});

// GET /api/levels/:levelId/status
app.get('/api/levels/:levelId/status', authenticatePlayer, (req, res) => {
  const levelId = parseInt(req.params.levelId, 10);

  if (!LEVEL_CONFIG[levelId]) {
    return res.status(404).json({ success: false, error: 'Level not found' });
  }

  const player = getOrCreatePlayer(req.playerId);
  const completion = player.levelsCompleted[levelId];
  const isUnlocked = levelId === 1 || !!player.levelsCompleted[levelId - 1];

  const config = LEVEL_CONFIG[levelId];

  res.json({
    success: true,
    data: {
      levelId,
      unlocked: isUnlocked,
      completed: !!completion,
      stars: completion?.stars || 0,
      bestScore: completion?.bestScore || 0,
      bestTime: completion?.bestTime || null,
      completionCount: completion?.completionCount || 0,
      starThresholds: config.starThresholds,
      maxTime: config.maxTime,
      possibleRewards: {
        oneStar: { coins: config.rewards.coins[0], gems: config.rewards.gems[0] },
        twoStars: { coins: config.rewards.coins[1], gems: config.rewards.gems[1] },
        threeStars: { coins: config.rewards.coins[2], gems: config.rewards.gems[2] },
      },
    },
  });
});

// GET /api/levels - list all levels with player progress
app.get('/api/levels', authenticatePlayer, (req, res) => {
  const player = getOrCreatePlayer(req.playerId);

  const levels = Object.entries(LEVEL_CONFIG).map(([id, config]) => {
    const levelId = parseInt(id, 10);
    const completion = player.levelsCompleted[levelId];
    const isUnlocked = levelId === 1 || !!player.levelsCompleted[levelId - 1];

    return {
      levelId,
      unlocked: isUnlocked,
      completed: !!completion,
      stars: completion?.stars || 0,
      bestScore: completion?.bestScore || 0,
      maxTime: config.maxTime,
    };
  });

  res.json({
    success: true,
    data: { levels, totalStars: player.totalStars },
  });
});

// POST /api/rewards/claim-milestone
app.post('/api/rewards/claim-milestone', authenticatePlayer, (req, res) => {
  const { milestoneStars } = req.body;

  if (!milestoneStars || !MILESTONE_REWARDS[milestoneStars]) {
    return res.status(400).json({
      success: false,
      error: 'Invalid milestone. Available milestones: ' + Object.keys(MILESTONE_REWARDS).join(', '),
    });
  }

  const player = getOrCreatePlayer(req.playerId);

  // Check if player has enough stars
  if (player.totalStars < milestoneStars) {
    return res.status(403).json({
      success: false,
      error: `Not enough stars. Need ${milestoneStars}, have ${player.totalStars}.`,
    });
  }

  // Check if already claimed
  const claimKey = `${req.playerId}_milestone_${milestoneStars}`;
  if (claimedRewards[claimKey]) {
    return res.status(409).json({
      success: false,
      error: 'Milestone reward already claimed.',
      claimedAt: claimedRewards[claimKey].claimedAt,
    });
  }

  // Award milestone reward
  const reward = MILESTONE_REWARDS[milestoneStars];
  player.coins += reward.coins;
  player.gems += reward.gems;
  if (reward.item) {
    player.items.push({
      id: crypto.randomUUID(),
      type: reward.item,
      obtainedAt: new Date().toISOString(),
      source: `milestone_${milestoneStars}`,
    });
  }

  // Mark as claimed
  claimedRewards[claimKey] = {
    playerId: req.playerId,
    milestoneStars,
    reward,
    claimedAt: new Date().toISOString(),
  };

  res.json({
    success: true,
    data: {
      milestoneStars,
      reward: {
        coins: reward.coins,
        gems: reward.gems,
        item: reward.item || null,
      },
      playerState: {
        coins: player.coins,
        gems: player.gems,
        totalStars: player.totalStars,
        items: player.items,
      },
      message: `Milestone reward claimed! +${reward.coins} coins, +${reward.gems} gems${reward.item ? ', +' + reward.item : ''}`,
    },
  });
});

// GET /api/rewards/milestones - list all milestones with claim status
app.get('/api/rewards/milestones', authenticatePlayer, (req, res) => {
  const player = getOrCreatePlayer(req.playerId);

  const milestones = Object.entries(MILESTONE_REWARDS).map(([stars, reward]) => {
    const starsNum = parseInt(stars, 10);
    const claimKey = `${req.playerId}_milestone_${starsNum}`;
    const claimed = !!claimedRewards[claimKey];
    const unlocked = player.totalStars >= starsNum;

    return {
      starsRequired: starsNum,
      unlocked,
      claimed,
      claimedAt: claimedRewards[claimKey]?.claimedAt || null,
      reward: {
        coins: reward.coins,
        gems: reward.gems,
        item: reward.item || null,
      },
    };
  });

  res.json({
    success: true,
    data: {
      totalStars: player.totalStars,
      milestones,
    },
  });
});

// POST /api/rewards/daily - claim daily login reward
const dailyRewards = {};
const DAILY_REWARD_TIERS = [
  { coins: 20, gems: 0 },
  { coins: 30, gems: 1 },
  { coins: 40, gems: 1 },
  { coins: 50, gems: 2 },
  { coins: 75, gems: 3 },
  { coins: 100, gems: 5 },
  { coins: 150, gems: 10 },
];

app.post('/api/rewards/daily', authenticatePlayer, (req, res) => {
  const player = getOrCreatePlayer(req.playerId);
  const today = new Date().toISOString().split('T')[0];

  if (!dailyRewards[req.playerId]) {
    dailyRewards[req.playerId] = {
      lastClaimDate: null,
      streak: 0,
      totalClaims: 0,
    };
  }

  const dailyState = dailyRewards[req.playerId];

  // Check if already claimed today
  if (dailyState.lastClaimDate === today) {
    return res.status(409).json({
      success: false,
      error: 'Daily reward already claimed today.',
      nextClaimDate: getNextDay(today),
      currentStreak: dailyState.streak,
    });
  }

  // Check streak continuity
  const yesterday = getNextDay(today, -1);
  if (dailyState.lastClaimDate === yesterday) {
    dailyState.streak = Math.min(dailyState.streak + 1, DAILY_REWARD_TIERS.length - 1);
  } else {
    dailyState.streak = 0; // Reset streak
  }

  const tierIndex = dailyState.streak;
  const reward = DAILY_REWARD_TIERS[tierIndex];

  // Award reward
  player.coins += reward.coins;
  player.gems += reward.gems;

  dailyState.lastClaimDate = today;
  dailyState.totalClaims += 1;

  res.json({
    success: true,
    data: {
      day: tierIndex + 1,
      streak: dailyState.streak + 1,
      maxStreak: DAILY_REWARD_TIERS.length,
      reward: {
        coins: reward.coins,
        gems: reward.gems,
      },
      nextReward: DAILY_REWARD_TIERS[Math.min(tierIndex + 1, DAILY_REWARD_TIERS.length - 1)],
      playerState: {
        coins: player.coins,
        gems: player.gems,
      },
      message: `Day ${tierIndex + 1} reward claimed! +${reward.coins} coins, +${reward.gems} gems`,
    },
  });
});

// GET /api/rewards/daily/status
app.get('/api/rewards/daily/status', authenticatePlayer, (req, res) => {
  const today = new Date().toISOString().split('T')[0];
  const dailyState = dailyRewards[req.playerId] || { lastClaimDate: null, streak: 0, totalClaims: 0 };

  const claimedToday = dailyState.lastClaimDate === today;
  const yesterday = getNextDay(today, -1);
  const currentStreak = dailyState.lastClaimDate === yesterday || dailyState.lastClaimDate === today
    ? dailyState.streak
    : 0;

  res.json({
    success: true,
    data: {
      claimedToday,
      currentStreak: currentStreak + 1,
      maxStreak: DAILY_REWARD_TIERS.length,
      nextReward: claimedToday
        ? DAILY_REWARD_TIERS[Math.min(currentStreak + 1, DAILY_REWARD_TIERS.length - 1)]
        : DAILY_REWARD_TIERS[currentStreak],
      allTiers: DAILY_REWARD_TIERS.map((tier, index) => ({
        day: index + 1,
        ...tier,
        claimed: index <= currentStreak && claimedToday,
        current: index === (claimedToday ? currentStreak + 1 : currentStreak),
      })),
    },
  });
});

// GET /api/player/history - get completion history
app.get('/api/player/history', authenticatePlayer, (req, res) => {
  const history = levelCompletions[req.playerId] || [];
  const { levelId, limit = 20, offset = 0 } = req.query;

  let filtered = history;
  if (levelId) {
    filtered = filtered.filter(c => c.levelId === parseInt(levelId, 10));
  }

  const total = filtered.length;
  const paginated = filtered
    .sort((a, b) => new Date(b.completedAt) - new Date(a.completedAt))
    .slice(parseInt(offset, 10), parseInt(offset, 10) + parseInt(limit, 10));

  res.json({
    success: true,
    data: {
      completions: paginated,
      pagination: {
        total,
        limit: parseInt(limit, 10),
        offset: parseInt(offset, 10),
        hasMore: parseInt(offset, 10) + parseInt(limit, 10) < total,
      },
    },
  });
});

// GET /api/leaderboard/:levelId
const leaderboards = {};

app.get('/api/leaderboard/:levelId', (req, res) => {
  const levelId = parseInt(req.params.levelId, 10);

  if (!LEVEL_CONFIG[levelId]) {
    return res.status(404).json({ success: false, error: 'Level not found' });
  }

  // Build leaderboard from all player completions
  const entries = [];
  for (const [playerId, player] of Object.entries(players)) {
    const completion = player.levelsCompleted[levelId];
    if (completion) {
      entries.push({
        playerId,
        playerName: player.name || playerId.substring(0, 8),
        score: completion.bestScore,
        stars: completion.stars,
        bestTime: completion.bestTime,
      });
    }
  }

  entries.sort((a, b) => b.score - a.score || a.bestTime - b.bestTime);

  const top = entries.slice(0, 50).map((entry, index) => ({
    rank: index + 1,
    ...entry,
  }));

  res.json({
    success: true,
    data: {
      levelId,
      leaderboard: top,
      totalPlayers: entries.length,
    },
  });
});

// Utility: get next/previous day string
function getNextDay(dateStr, offset = 1) {
  const date = new Date(dateStr);
  date.setDate(date.getDate() + offset);
  return date.toISOString().split('T')[0];
}

// Error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({
    success: false,
    error: 'Internal server error',
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({
    success: false,
    error: 'Endpoint not found',
  });
});

